noncompliant:
public class EventLog
{
    public DateTime Timestamp { get; set; } // Noncompliant - no timezone info

    public void LogEvent(string message)
    {
        Timestamp = DateTime.Now; // Noncompliant - loses timezone
    }

    public DateTime GetUtcTime()
    {
        return DateTime.UtcNow; // Noncompliant - prefer DateTimeOffset
    }
}

compliant:
public class EventLog
{
    public DateTimeOffset Timestamp { get; set; } // Compliant - includes offset

    public void LogEvent(string message)
    {
        Timestamp = DateTimeOffset.Now; // Compliant - preserves offset
    }

    public DateTimeOffset GetUtcTime()
    {
        return DateTimeOffset.UtcNow; // Compliant
    }
}
